// TestAnalyzerRegistryContract verifies that the analyzer registry correctly
// classifies languages: returns nil for unsupported languages (Swift) and
// non-nil for supported languages (go, ts, js, py, rs).
func TestAnalyzerRegistryContract(t *testing.T) {
	tests := []struct {
		name        string
		lang        string
		wantNil     bool
		description string
	}{
		// Unsupported languages - should return nil
		{name: "Swift unsupported", lang: "swift", wantNil: true, description: "Swift should return nil (unsupported)"},
		{name: "Swift short form", lang: "swift", wantNil: true, description: "Swift short form should return nil"},

		// Supported languages - should return non-nil analyzer
		{name: "Go supported", lang: "go", wantNil: false, description: "Go should return non-nil analyzer"},
		{name: "TypeScript supported", lang: "ts", wantNil: false, description: "TypeScript should return non-nil analyzer"},
		{name: "JavaScript supported", lang: "js", wantNil: false, description: "JavaScript should return non-nil analyzer"},
		{name: "Python supported", lang: "py", wantNil: false, description: "Python should return non-nil analyzer"},
		{name: "Rust supported", lang: "rs", wantNil: false, description: "Rust should return non-nil analyzer"},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := analysis.ForLanguage(tt.lang)
			if tt.wantNil && got != nil {
				t.Errorf("ForLanguage(%q) = %v, want nil (%s)", tt.lang, got, tt.description)
			}
			if !tt.wantNil && got == nil {
				t.Errorf("ForLanguage(%q) = nil, want non-nil (%s)", tt.lang, tt.description)
			}
		})
	}
}

// TestCertifierEmitsNAForUnsupportedLanguage verifies that the certifier
// produces an N/A grade for units with unsupported languages (e.g., Swift).
func TestCertifierEmitsNAForUnsupportedLanguage(t *testing.T) {
	// Create a certifier instance
	certifier := NewCertifier(nil)

	// Create a unit with an unsupported language (Swift)
	unit := &domain.Unit{
		ID:       "test-swift-unit",
		Language: "swift",
		Path:     "test.swift",
	}

	// Certify the unit
	result := certifier.CertifyUnit(unit)

	// The result should exist and have appropriate handling for unsupported language
	if result == nil {
		t.Fatal("CertifyUnit returned nil for unsupported language")
	}

	// Check that the result indicates no certification could be performed
	// This could be via Score = 0, Grade = "N/A", or specific error conditions
	if result.Grade == "A" || result.Grade == "B" || result.Grade == "C" {
		t.Errorf("CertifyUnit for Swift produced a letter grade %q, expected N/A or empty for unsupported language", result.Grade)
	}
}

